Script.script:
function Advent_days()
  if os.date("%m", os.time()) < "12" then
    return 24
  end
  return math.min(24, tonumber(os.date("%d", os.time())))
end

function this_year()
  return os.date("%Y", os.time())
end

function get_year(delta)
  delta = delta or 0
  local result = f"{tonumber(this_year())+delta}"
  return result
end

HintRegistryTemplate.alias_templates = { { "Neues Ziel erfragen", "^#{self:shortname()}neu$", [[ ---@pattern #{self:shortname()}neu {self:name()}:trigger_hint() ]] }, { "Ziele auflisten", "^#{self:shortname()}list(\\s(\\d+))?$", [[ ---@pattern #{self:shortname()}list <Jahr>? ---@desc Liste alle Ziele fuer das Jahr auf. ---@desc Ohne Jahr wird das aktuelle Jahr genommen. {self:name()}:all_targets(matches[3]) ]] }, { "Offene Ziele auflisten", "^#{self:shortname()}listtodo(\\s(\\d+))?$", [[ ---@pattern #{self:shortname()}listtodo <Jahr>? ---@desc Liste alle unerledigten Ziele fuer das Jahr auf. ---@desc Ohne Jahr wird das aktuelle Jahr genommen. {self:name()}:all_targets(tonumber(matches[3]), true) ]] }, { "Ziele suchen", "^#{self:shortname()}find (.+)?$", [[ ---@pattern #{self:shortname()}find <Text>? ---@desc Liste alle Ziele auf, dessen Hinweis zum ---@desc Text passt {self:name()}:find_targets(matches[2]) ]] }, { "Ziel Details", "^#{self:shortname()} (\\d+)$", [[ ---@pattern #{self:shortname()} <ID> ---@desc Gib alle Details zu einem Ziel mit der ID <ID> an. {self:name()}:single_target(tonumber(matches[2])) ]] }, { "Ziel als gefunden markieren", "^#{self:shortname()}check (\\d+)(\\s(\\d+))?$", [[ ---@pattern #{self:shortname()}check <Ziel ID> <Jahr>? ---@desc Markiere das Ziel mit der ID fuer das Jahr ---@desc als erledigt an. Ohne das Jahr wird das ---@desc aktuelle Jahr genommen. ---@desc Sonderfall: Bei Zaubertraenken sollte das ---@desc Jahr weggelassen werden. {self:name()}:target_done(tonumber(matches[2]), tonumber(matches[4])) ]] }, { "Ziel wieder als offen markieren", "^#{self:shortname()}uncheck (\\d+)(\\s(\\d+))?$", [[ ---@pattern #{self:shortname()}check <Ziel ID> <Jahr>? ---@desc Markiere das Ziel mit der ID fuer das Jahr ---@desc wieder als offen an. Ohne das Jahr wird das ---@desc aktuelle Jahr genommen. ---@desc Sonderfall: Bei Zaubertraenken sollte das ---@desc Jahr weggelassen werden. {self:name()}:open_target(tonumber(matches[2]), tonumber(matches[4])) ]] }, { "Ziel loeschen", "^#{self:shortname()}del (\\d+)$", [[ ---@pattern #{self:shortname()}del <ID> {self:name()}:delete_target(tonumber(matches[2])) ]] }, { "Ziel Kurzhinweis aendern", "^#{self:shortname()}short (\\d+) (.+)$", [[ ---@pattern #{self:shortname()}short <ID> <Inhalt> ---@desc Ersetze den Kurzhinweis des Ziels <ID> mit <Inhalt> {self:name()}:change_target_short(tonumber(matches[2]), matches[3]) ]] }, { "Ziel Notiz hinzufuegen/aendern", "^#{self:shortname()}note (\\d+) (\\d+) (\\s(.*))?$", [[ ---@pattern #{self:shortname()}note <ID> <Notizposition> <Inhalt> ---@desc Falls die Notizposition groesser ist als die Liste, ---@desc dann wird die Notiz am Ende hinzugefuegt. ---@desc Ansonsten wird die Notiz mit dem Inhalt ersetzt. ---@desc Der Inhalt kann dabei weggelassen werden um den entsprechenden ---@desc Notiz zu loeschen. {self:name()}:change_target_note(tonumber(matches[2]), tonumber(matches[3]), matches[5]) ]] }, { "Ziele vereinen", "^#{self:shortname()}merge (\\d+) (\\d+)$", [[ ---@pattern #{self:shortname()}merge <ID1> <ID2> ---@desc Verschmelze die beiden Ziele zu einem Ziel und vereine Hinweise ---@desc und Notizen. {self:name()}:merge_targets(tonumber(matches[2]), tonumber(matches[3])) ]] }, { "Ziele teilen", "^#{self:shortname()}split (\\d+)$", [[ ---@pattern #{self:shortname()}split <ID> ---@desc Zerlege eine verschmolzenen Hinweis wieder in Einzelhinweise. {self:name()}:split_targets(tonumber(matches[2])) ]] }
}
function HintRegistryTemplate:create_aliases() local group = self:name() if exists(group, "alias") == 0 then self:info(f"Build alias group {group}") permGroup(group, "alias", self._module) end for _, alias in pairs(self.alias_templates) do local name, regex, script = unpack(alias) local known = false for _, aid in pairs(findItems(name, "alias")) do known = ancestors(aid, "alias")[1].name == group if known then break end end if not known then permAlias(name, group, f(regex), f(script)) end end end

function ChristmasThiefRegistry:announce_text(known_target, new_target, target) local result = HintRegistryTemplate.announce_text(self, known_target, new_target, target) if target.npc_id then for _, npc in pairs(EK.data.npcs) do if npc._id == target.npc_id then result = f"{result}
EK zugewiesen: {target.npc_id} - {npc.name} - {npc.ort} - {npc.region}" return result end end result = f"{result}
EK-ID {target.npc_id} gefunden, aber kein NPC-Datensatz passt dazu." else result = f"{result}
Kein EK zugewiesen." end return result end

drop_lines = {
  "Folgenden Tipp habe ich fuer Dich:",
  "Wenn Du alle Tipps auf einmal hoeren willst, frage mich",
  "nach 'tipps'."
}

function EasterEggRegistry:filter_line(line)
  return not table.contains(drop_lines, line) and line
end

PotionRegistry = PotionRegistry or HintRegistryTemplate:new{
  _name = "PotionRegistry",
  _shortname = "ZT",
  _module = "HintRegistry",
  _version = "1.0.0",
  config = {
    prefix = "",
    trigger = "zaubertraenke"
  },
  limit = function() return 40 end,
  _fixed_version={MundronClassMethods="1.1.0", HintRegistryTemplate="2.0.0"}
}

ZT = PotionRegistry
